SELECT * FROM products;
SELECT  product_name,  category, vendor_location FROM products;
SELECT * FROM products WHERE category = 'Skincare';
SELECT * FROM sales_orders WHERE unit_sold > 500;
SELECT sku, SUM(unit_sold) AS  total_units_sold FROM sales_orders GROUP BY sku;
SELECT products.product_name, products.category, sales_orders.sku, SUM(sales_orders.unit_sold) AS total_units_sold FROM sales_orders JOIN products ON sales_orders.sku = products.sku GROUP BY sales_orders.sku, products.product_name, products.category ORDER BY total_units_sold DESC;
SELECT products.category, SUM(sales_orders.unit_sold) AS total_units_sold FROM sales_orders JOIN products ON sales_orders.sku = products.sku GROUP BY products.category ORDER BY total_units_sold DESC;
SELECT products.product_name, products.category,sales_orders.sku, SUM(sales_orders.unit_sold) AS total_units_sold, SUM(sales_orders.forecast_qty) AS total_forecast_qty, SUM(sales_orders.unit_sold) - SUM(sales_orders.forecast_qty) AS forecast_gap FROM sales_orders JOIN products on sales_orders.sku = products.sku GROUP BY sales_orders.sku, products.product_name, products.category ORDER BY forecast_gap DESC;
SELECT products.product_name, products.category, inventory_snapshot.sku, inventory_snapshot.on_hand_units, inventory_snapshot.committed_units, inventory_snapshot.qa_hold_units, inventory_snapshot.on_hand_units - inventory_snapshot.committed_units - inventory_snapshot.qa_hold_units AS net_available_units FROM inventory_snapshot JOIN products on inventory_snapshot.sku = products.sku ORDER BY net_available_units ASC;
SELECT sku, SUM(unit_sold) AS total_units_sold, ROUND(SUM(unit_sold) / 12.0, 1) AS avg_weekly_demand FROM sales_orders GROUP BY sku ORDER BY avg_weekly_demand DESC;
SELECT products.product_name, products.category, inventory_snapshot.sku, inventory_snapshot.on_hand_units - inventory_snapshot.committed_units - inventory_snapshot.qa_hold_units AS net_available_units, ROUND(SUM(sales_orders.unit_sold) / 12.0, 1) AS avg_weekly_demand, ROUND((inventory_snapshot.on_hand_units - inventory_snapshot.committed_units - inventory_snapshot.qa_hold_units) / (SUM(sales_orders.unit_sold) / 12.0), 2) AS weeks_of_supply FROM inventory_snapshot JOIN products ON inventory_snapshot.sku = products.sku JOIN sales_orders on inventory_snapshot.sku = sales_orders.sku GROUP BY inventory_snapshot.sku, products.product_name, products.category, inventory_snapshot.on_hand_units, inventory_snapshot.committed_units, inventory_snapshot.qa_hold_units ORDER BY 6 ASC;
